import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"百兵皆艺","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/百兵皆艺.md","filePath":"4.资源分区/6.技艺及称号/武技类/百兵皆艺.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/百兵皆艺.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"百兵皆艺",tabindex:"-1"},[p("百兵皆艺 "),r("a",{class:"header-anchor",href:"#百兵皆艺","aria-label":'Permalink to "百兵皆艺"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001E")])])],-1),n('<h1 id="百兵皆艺-1" tabindex="-1">百兵皆艺 <a class="header-anchor" href="#百兵皆艺-1" aria-label="Permalink to &quot;百兵皆艺&quot;">​</a></h1><p>百兵皆艺<br> D+500<br> 世间武器如此之多，所研习者穷尽一生也无法尽数习得，偏有这样的一类人，醉心于各种武器的使用，把不同武器的性能所发挥的淋漓尽致，向敢于挑衅的敌人发起怒海狂涛一般的致命艺术，有一个格外响亮的名字来称呼他们——“武器大师”。<br> 而在这个群体当中，曾有一位堪称极境之人，本兑换即是重走他修行技艺的道路。<br> 特殊的是，本资源内所提及的武器也包括天生武器在内，如果一把武器可以造成多种性质的伤害，每有一种伤害性质视为额外一把武器来计算武器的数量。</p><p>神意：你获得一种特殊的能量池，关键属性为【决心+感知】/2，不视为正常能量池，因此不会被相关能力或判定影响，也不能作为能量池驱动其他技艺，或代替消耗。<br> 神意是使用相关技艺的前提条件，会在每个回合开始时回满。</p><p>骤雨连打：匕首，枪械，重剑，长鞭，花枪，刺刀……诸如此类，种种武器在他手中随心而动，如同倾盆暴雨一般向敌人泼去。<br> 你进行攻击时每有1点传奇敏捷，就额外造成1点多次攻击减值，这要求你必须使用不同的武器进行攻击。</p><p>百兵皆通：刀枪棍棒十八般兵器样样精通可不足够形容，随着阅历的增加对各种兵器也将会越发熟悉。<br> 每经过一场影片，你就获得1级自由分配在武技或者射击上的专业，任意选择具体类型。</p><p>百兵相关专长<br> 十全武道（1-3）<br> 你必须持有至少一把以上武器施展本专长<br> 1级：乱星<br> 当你以不同武器进行时，每额外攻击1次，敌人就多承受1点多次攻击减值（上限专长等级）。<br> 不视为额外的攻击，而是衔接紧密的连环打击使敌人应接不暇。<br> 2级：兵库<br> 你具有20立方米的储物空间，主要是储存武器，默认表现方式是以不可思议的情况携带在身上，但也可以如常进行储物表现。<br> 仅限本资源所提及的多次攻击时，你可以无需把武器从储物空间里主动取出的直接满足持有多武器前提，也不必切换手中的武器，但画面效果视为已取出并切换。<br> 3级：至极<br> 武器相关专业每有6级，你就可以选择一个任意武器专业，使用本专业进行的攻击中获得1DP修行加值。<br> 因此获得了至少1点加值时，在进行对应类型的专业格挡时还会额外获得1DP。</p><p>谢幕（2）<br> 你必须持有至少一把以上武器施展本技艺<br> 2级：终结<br> 每轮一次，在你进行以本技艺主干的额外攻击结束后，可以消费移动动作追加一次冲撞，如果成功击退，再单独以攻击对应属性进行一次检定，不计入属性附加成功，每有3点成功数，本次冲撞就会造成1点伤害，伤害上限击退/米。</p><p>百兵相关技艺<br> 相关能耗皆为神意值</p><p>方寸一剑<br> 价格：D+500<br> 动作：标准动作<br> 能耗：0<br> 描述：无论是哪一种武器，最基础的便是“轰”在敌人身上，无所谓用法，因为在短兵相接，生死一瞬的战斗中就没有考量的时间。<br> 也无所谓理由，或者什么其他的东西，他的剑不能搬山，不能断海，不能开天，而是实实在在的杀人剑，因为冷兵器所及之处有方寸之长，因此本技艺又称“方寸杀人剑”。<br> 效果：立刻进行一次全力普通攻击，挥舞武器向敌人发起攻击，允许与其他招式一同使用。<br> 增幅：本主干提供的额外攻击次数每有1点，你就可以多消耗1点神意值，使这次攻击增加2DP修行加值。</p><p>瞬尘剑<br> 价格：D+500<br> 动作：整轮动作<br> 能耗：1<br> 描述：极高速的突刺攻击，比风更快的速度，分毫不减的灵活性，即使连地面的灰尘也不会扬起，也是这招名字的由来。<br> 他曾在年少时凭这招夺取了超过百人的性命。<br> 效果：稳住上半身，向敌人进行音速突刺，这视为一次冲锋攻击来结算相关效果，但会额外获得高速5，同时结算时少降低2点基础防御。<br> 研发：C+1000 允许曲线冲锋，即使在困难地形也能如常冲锋，同时冲锋中基础移动速度视为增加15米结算。。</p><p>蛮横挥击<br> 价格：D+500<br> 动作：标准动作<br> 能耗：1<br> 描述：更加狂野的打法，肆意挥舞大体积的武器对敌人进行猛烈打击，简单而有效，是直接砸成碎片的风格，于重甲单位堪称噩梦。<br> 效果：进行一次标准的攻击，本次攻击附带【威猛1】。<br> 如果本次攻击中至少包含了一把体积不低于3点的双手重武器进行的打击，那么还会额外获得【破甲5】。</p><p>止水一击<br> 价格：C+1000<br> 动作：标准动作<br> 能耗：3<br> 描述：明镜止水的心境为居合一道追求的境界，以至静化至动往往能够爆发出更强劲的威能，所谓在这样的心境下放出的神速攻击，也被称为居合斩，在他手中以多种武器来言也不外乎如此。<br> 也就是说，首先是将武器收入鞘，然后把心委于水流，再快速拨出，乘着水流，让所有敌人都沐浴在无数的斩击之中，也同样切断了心中的流水，这就是止水的一击。<br> 效果：进行一次标准攻击，同时攻击接触范围内的所有敌人，不论武器类型的满足拔刀斩前提（包括枪械，视为美式居合，购买剑鞘时可以改为枪套），只需要一个移动动作就能将主干涉及到多次攻击使用过的武器全部入鞘。</p><p>枪剑双绝<br> 价格：C+1000<br> 动作：标准动作<br> 能耗：3<br> 描述：他扬起剑刃，做势欲劈，可当对手全神贯注的戒备这次攻击时，只听惊雷一响，身上便被开了数个血洞，余下枪口硝烟在空气中散去。<br> “都什么年代了还用传统冷兵器？”<br> 效果：选择一个你可以白刃攻击到的单位，以武技+白刃相关专业进行一次检定，你在对其进行的下一次攻击获得等同成功数的高速，<br> 随后，你进行一次枪械射击攻击，你也可以不进行本次攻击，而是在本轮内的下次攻击后追加一次枪械攻击（这没有好处，只代表你可以把这次该有的攻击延迟到下次一起攻击的表现）。</p><p>完美节奏<br> 价格：B+2000<br> 动作：被动<br> 描述：随着战斗的进行，一举一动逐渐处于掌控之中，武器如同艺术一样划过更加优美的弧度，如同敌人在迎合剑刃一般，看到的人不得不承认这样的战斗方式是如此超凡脱俗。<br> 效果：每轮一次，在你进行本主干提及的额外攻击结算后，可以获得以下所有效果，数值可叠加。<br> -在表现上视为攻击次数增加，但不造成多次攻击减值，也不承受武器数量限制，而是在攻击时获得本主干提供的额外攻击次数/1DP的表现加值。<br> -在防御时获得本主干提供的额外攻击次数/1DP的格挡加值。<br> -在攻击时可选择将伤害转为精神伤害<br> 战斗结束后失去本能力带来的加值。<br> 研发（B+2000）：不仅是在战斗内，精进的武艺同样可以保留到战斗外。<br> 实际效果为在战斗结束后，可选择保留1点完美节奏所提供的加值，可选择保留攻击标准加值或防御格挡加值，后者提供的是常态存在的格挡加值。<br> 每天最多只能凭此效果保留1点加值，每场影片最多在这项能力中获得6点加值。<br> 研发后你可以把攻击检定改为反射豁免而不是正常防御对抗，这视为战斗中敌人必须力竭躲闪你的攻击，否则就会被致命的剑刃直接贯穿。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
